p_h1(u'\u0432\u0432\u0435\u0434\u0435\u043d\u0438\u0435')
p_body(u'\u0410\u043a\u0442\u0443\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u044c. \u0426\u0438\u0444\u0440\u043e\u0432\u044b\u0435 \u0434\u0432\u043e\u0439\u043d\u0438\u043a\u0438 (Digital Twin) \u043e\u0445\u0432\u0430\u0442\u044b\u0432\u0430\u044e\u0442 \u0432\u0441\u0435 \u0431\u043e\u043b\u044c\u0448\u0435\u0435 \u043f\u0440\u0438\u043c\u0435\u043d\u0435\u043d\u0438\u0435 \u0432 \u043c\u0435\u0445\u0430\u0442\u0440\u043e\u043d\u0438\u043a\u0435, \u0440\u043e\u0431\u043e\u0442\u043e\u0442\u0435\u0445\u043d\u0438\u043a\u0435 \u0438 \u043f\u0440\u043e\u043c\u044b\u0448\u043b\u0435\u043d\u043d\u043e\u0439 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0437\u0430\u0446\u0438\u0438. \u041a\u043e\u043d\u0446\u0435\u043f\u0446\u0438\u044f \u0446\u0438\u0444\u0440\u043e\u0432\u043e\u0433\u043e \u0434\u0432\u043e\u0439\u043d\u0438\u043a\u0430 \u043f\u043e \u041c.\u0413\u0440\u0438\u0432\u0441\u0443 (Grieves, 2014) \u0432\u043a\u043b\u044e\u0447\u0430\u0435\u0442 \u0442\u0440\u0438 \u043a\u043e\u043c\u043f\u043e\u043d\u0435\u043d\u0442\u0430: \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0430\u043a\u0442\u0438\u0432 (Physical Twin), \u0446\u0438\u0444\u0440\u043e\u0432\u043e\u0439 \u043f\u043e\u0442\u043e\u043a \u0434\u0430\u043d\u043d\u044b\u0445 (Digital Thread) \u0438 \u0432\u0438\u0440\u0442\u0443\u0430\u043b\u044c\u043d\u044b\u0439 \u0434\u0432\u043e\u0439\u043d\u0438\u043a (Virtual Twin). \u0411\u0435\u0441\u043a\u043e\u043b\u043b\u0435\u043a\u0442\u043e\u0440\u043d\u044b\u0435 \u0434\u0432\u0438\u0433\u0430\u0442\u0435\u043b\u0438 \u043f\u043e\u0441\u0442\u043e\u044f\u043d\u043d\u043e\u0433\u043e \u0442\u043e\u043a\u0430 (\u0411\u0414\u041f\u0422) \u044f\u0432\u043b\u044f\u044e\u0442\u0441\u044f \u043a\u043b\u044e\u0447\u0435\u0432\u044b\u043c\u0438 \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u0430\u043c\u0438 \u0441\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u044b\u0445 \u043c\u0435\u0445\u0430\u0442\u0440\u043e\u043d\u043d\u044b\u0445 \u0441\u0438\u0441\u0442\u0435\u043c, AGV-\u0440\u043e\u0431\u043e\u0442\u043e\u0432 \u0438 \u0442\u043e\u0447\u043d\u044b\u0445 \u043b\u0438\u043d\u0435\u0439\u043d\u044b\u0445 \u0430\u043a\u0442\u0443\u0430\u0442\u043e\u0440\u043e\u0432. \u041f\u0440\u0435\u0434\u0438\u043a\u0442\u0438\u0432\u043d\u043e\u0435 \u043e\u0431\u0441\u043b\u0443\u0436\u0438\u0432\u0430\u043d\u0438\u0435 (Predictive Maintenance) \u043d\u0430 \u043e\u0441\u043d\u043e\u0432\u0435 \u0446\u0438\u0444\u0440\u043e\u0432\u043e\u0433\u043e \u0434\u0432\u043e\u0439\u043d\u0438\u043a\u0430 \u043f\u043e\u0437\u0432\u043e\u043b\u044f\u0435\u0442 \u0441\u043e\u043a\u0440\u0430\u0442\u0438\u0442\u044c \u043d\u0435\u0437\u0430\u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0435 \u043f\u0440\u043e\u0441\u0442\u043e\u0438 \u0438 \u043f\u043e\u0432\u044b\u0441\u0438\u0442\u044c \u043d\u0430\u0434\u0451\u0436\u043d\u043e\u0441\u0442\u044c \u043e\u0431\u043e\u0440\u0443\u0434\u043e\u0432\u0430\u043d\u0438\u044f.')
p_body(u'\u0426\u0435\u043b\u044c \u0440\u0430\u0431\u043e\u0442\u044b: \u0440\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u043a\u0430 \u043f\u0440\u043e\u0433\u0440\u0430\u043c\u043c\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0442\u043e\u0442\u0438\u043f\u0430 \u0446\u0438\u0444\u0440\u043e\u0432\u043e\u0433\u043e \u0434\u0432\u043e\u0439\u043d\u0438\u043a\u0430 (LADTS \u2014 Linear Actuator Digital Twin Simulator) \u043b\u0438\u043d\u0435\u0439\u043d\u043e\u0433\u043e \u044d\u043b\u0435\u043a\u0442\u0440\u043e\u043c\u0435\u0445\u0430\u043d\u0438\u0447\u0435\u0441\u043a\u043e\u0433\u043e \u043f\u0440\u0438\u0432\u043e\u0434\u0430 \u043d\u0430 \u0431\u0430\u0437\u0435 \u0411\u0414\u041f\u0422 Oriental Motor BLH5100KC (100 \u0412\u0442), \u0440\u0435\u0430\u043b\u0438\u0437\u0443\u044e\u0449\u0435\u0433\u043e \u043f\u043e\u043b\u043d\u044b\u0439 \u0446\u0438\u043a\u043b: Physical Twin \u2192 Digital Thread \u2192 Virtual Twin.')
p_body(u'\u041e\u0431\u044a\u0435\u043a\u0442 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f: \u043b\u0438\u043d\u0435\u0439\u043d\u044b\u0439 \u0430\u043a\u0442\u0443\u0430\u0442\u043e\u0440 \u043d\u0430 \u0431\u0430\u0437\u0435 BDPT BLH5100KC \u0441 \u0448\u0430\u0440\u0438\u043a\u043e-\u0432\u0438\u043d\u0442\u043e\u0432\u043e\u0439 \u043f\u0435\u0440\u0435\u0434\u0430\u0447\u0435\u0439 (\u0428\u0412\u041f, \u0448\u0430\u0433 20 \u043c\u043c), \u0445\u043e\u0434 \u043a\u0430\u0440\u0435\u0442\u043a\u0438 300 \u043c\u043c.')
p_body(u'\u0417\u0430\u0434\u0430\u0447\u0438 \u0440\u0430\u0431\u043e\u0442\u044b:')
p_list(u'\u2014 \u0440\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u043a\u0430 \u043f\u043e\u043b\u043d\u043e\u0439 \u044d\u043b\u0435\u043a\u0442\u0440\u043e\u043c\u0435\u0445\u0430\u043d\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u043c\u043e\u0434\u0435\u043b\u0438 \u0444\u0430\u0437\u044b \u0411\u0414\u041f\u0422 \u0441 \u0434\u0438\u043d\u0430\u043c\u0438\u043a\u043e\u0439 \u0442\u043e\u043a\u0430;')
